import { Settings as SettingsIcon } from "lucide-react";

export function SettingsPage() {
  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-white">Settings</h1>
        <p className="text-gray-400 mt-1">Manage application settings and preferences</p>
      </div>

      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl p-12 flex flex-col items-center justify-center text-center min-h-[400px]">
        <div className="w-20 h-20 bg-[#39FF14]/10 rounded-full flex items-center justify-center mb-4">
          <SettingsIcon className="w-10 h-10 text-[#39FF14]" />
        </div>
        <h2 className="text-xl font-bold text-white mb-2">Application Settings</h2>
        <p className="text-gray-400 max-w-md">
          Configure gym settings, staff permissions, integrations, and system preferences.
        </p>
      </div>
    </div>
  );
}
